import sys
from collections import defaultdict

def main():
    sys.setrecursionlimit(10000)
    N, M = map(int, sys.stdin.readline().split())
    edges = []
    graph = defaultdict(list)
    for _ in range(M):
        a, b = map(int, sys.stdin.readline().split())
        edges.append((a, b))
        graph[a].append(b)

    # Build the adjacency list for the graph
    adj = defaultdict(list)
    for a, b in edges:
        adj[a].append(b)

    # Track all possible candidates for the strongest programmer
    candidates = set(range(1, N + 1))

    # DFS to find all possible candidates for the strongest programmer
    def dfs(node, visited):
        visited.add(node)
        for neighbor in adj[node]:
            if neighbor not in visited:
                dfs(neighbor, visited)
        return visited

    # For each node, check if it can be the strongest
    for candidate in range(1, N + 1):
        visited = set()
        dfs(candidate, visited)
        if len(visited) != N:
            candidates.discard(candidate)

    if len(candidates) == 1:
        print(candidates.pop())
    else:
        print(-1)

if __name__ == "__main__":
    main()
